import { css } from 'styled-components';

export const withStyledDraggables = (components: any): ReturnType<typeof createPlateUI> => {
  return withDraggables(components, [
    {
      keys: [ELEMENT_PARAGRAPH, ELEMENT_UL, ELEMENT_OL],
