        ELEMENT_CODE_BLOCK,
      ],
      onRenderDragHandle: ({ styles, ...props }) => (
        <Tippy {...grabberTooltipProps}>
          <button type="button" {...props} css={styles}>
            <DragIndicator
              style={{
                width: 18,
                height: 18,
                color: 'rgba(55, 53, 47, 0.3)',
              }}
            />
          </button>
        </Tippy>
      ),
    },
    {
      key: ELEMENT_H1,
      styles: {
        gutterLeft: css`
          padding: 2em 0 4px;
          font-size: 1.875em;
        `,
        blockToolbarWrapper: css`
          height: 1.3em;
        `,
      },
    },
    {
      key: ELEMENT_H2,
      styles: {
        gutterLeft: css`
          padding: 1.4em 0 1px;
          font-size: 1.5em;
        `,
        blockToolbarWrapper: css`
          height: 1.3em;
